import express from "express";
import path from "node:path";
import crypto from "node:crypto";
import { fileURLToPath } from "node:url";
import { createGameServices } from "./services/gameService.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const webDist = path.join(__dirname, "..", "webapp", "dist");

function safeErr(err) {
  return (
    err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err)
  );
}

function verifyTelegramInitData(initData, botToken) {
  const params = new URLSearchParams(initData || "");
  const hash = params.get("hash") || "";
  if (!hash) return { ok: false, error: "Missing Telegram session hash." };

  params.delete("hash");
  const sorted = [...params.entries()]
    .map(([key, value]) => `${key}=${value}`)
    .sort()
    .join("\n");

  const secret = crypto.createHmac("sha256", "WebAppData").update(botToken).digest();
  const digest = crypto.createHmac("sha256", secret).update(sorted).digest("hex");

  const valid = Buffer.from(digest, "hex").length === Buffer.from(hash, "hex").length &&
    crypto.timingSafeEqual(Buffer.from(digest, "hex"), Buffer.from(hash, "hex"));

  if (!valid) return { ok: false, error: "Telegram session check failed." };

  let user = null;
  try {
    user = JSON.parse(params.get("user") || "null");
  } catch {
    user = null;
  }

  return { ok: true, user };
}

export async function startServer(cfg) {
  const app = express();
  const services = await createGameServices(cfg);
  app.locals.services = services;

  app.use(express.json({ limit: "512kb" }));

  app.get("/health", (_req, res) => {
    res.json({ ok: true, service: "tapchef" });
  });

  app.post("/api/auth/bootstrap", async (req, res) => {
    try {
      const initData = String(req.body?.initData || "");
      if (!initData) return res.status(400).json({ ok: false, error: "Missing Telegram init data." });

      const verified = verifyTelegramInitData(initData, cfg.TELEGRAM_BOT_TOKEN);
      if (!verified.ok || !verified.user?.id) {
        return res.status(401).json({ ok: false, error: verified.error || "Telegram auth failed." });
      }

      const state = await services.bootstrapPlayer(verified.user);
      res.json({ ok: true, state });
    } catch (error) {
      console.error("[api] bootstrap failed", { error: safeErr(error) });
      res.status(500).json({ ok: false, error: "Could not load your kitchen." });
    }
  });

  app.post("/api/game/tap", async (req, res) => {
    try {
      const telegramUserId = String(req.body?.telegramUserId || "");
      const taps = Number(req.body?.taps || 1);
      if (!telegramUserId) return res.status(400).json({ ok: false, error: "Missing player." });

      const state = await services.tapIngredient(telegramUserId, taps);
      res.json({ ok: true, state });
    } catch (error) {
      console.error("[api] tap failed", { error: safeErr(error) });
      res.status(400).json({ ok: false, error: safeErr(error) || "Tap failed." });
    }
  });

  app.post("/api/game/cook", async (req, res) => {
    try {
      const telegramUserId = String(req.body?.telegramUserId || "");
      if (!telegramUserId) return res.status(400).json({ ok: false, error: "Missing player." });

      const state = await services.cookMeal(telegramUserId);
      res.json({ ok: true, state });
    } catch (error) {
      console.error("[api] cook failed", { error: safeErr(error) });
      res.status(400).json({ ok: false, error: safeErr(error) || "Could not cook now." });
    }
  });

  app.get("/api/leaderboard", async (req, res) => {
    try {
      const telegramUserId = String(req.query?.telegramUserId || "");
      const data = await services.getLeaderboard(telegramUserId);
      res.json({ ok: true, ...data });
    } catch (error) {
      console.error("[api] leaderboard failed", { error: safeErr(error) });
      res.status(500).json({ ok: false, error: "Could not load leaderboard." });
    }
  });

  app.use("/app", express.static(webDist));
  app.get("/app", (_req, res) => res.sendFile(path.join(webDist, "index.html")));
  app.get("/app/*splat", (_req, res) => res.sendFile(path.join(webDist, "index.html")));
  app.get("/", (_req, res) => res.redirect("/app"));

  await new Promise((resolve) => {
    app.listen(cfg.PORT, () => {
      console.log("[server] listening", { port: cfg.PORT });
      resolve();
    });
  });

  let memTick = 0;
  setInterval(() => {
    memTick += 1;
    const m = process.memoryUsage();
    console.log("[mem]", {
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6),
      tick: memTick
    });
  }, 60000).unref();

  return app;
}

gameService.js.content:
import { getDb } from "../lib/db.js";

const MAX_ENERGY = 30;
const ENERGY_REFILL_MINUTES = 5;
const POINTS_PER_TAP = 1;
const TAPS_PER_MEAL = 20;
const MEAL_REWARD = 15;
const DAILY_TASKS = [
  { id: "open_kitchen", label: "Open the kitchen today", type: "open", target: 1 },
  { id: "tap_50", label: "Tap 50 ingredients", type: "tap", target: 50 },
  { id: "cook_3", label: "Cook 3 meals", type: "meal", target: 3 }
];

function safeErr(err) {
  return (
    err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err)
  );
}

function todayKey() {
  return new Date().toISOString().slice(0, 10);
}

function yesterdayKey() {
  const d = new Date();
  d.setUTCDate(d.getUTCDate() - 1);
  return d.toISOString().slice(0, 10);
}

function regenEnergy(user) {
  const now = new Date();
  const current = Number(user.currentEnergy ?? MAX_ENERGY);
  const updatedAt = new Date(user.energyUpdatedAt || now);
  const elapsedMinutes = Math.floor((now.getTime() - updatedAt.getTime()) / 60000);
  const restored = Math.floor(elapsedMinutes / ENERGY_REFILL_MINUTES);
  const nextEnergy = Math.min(user.maxEnergy || MAX_ENERGY, current + Math.max(0, restored));
  return {
    currentEnergy: nextEnergy,
    energyUpdatedAt: nextEnergy >= (user.maxEnergy || MAX_ENERGY)
      ? now
      : new Date(updatedAt.getTime() + restored * ENERGY_REFILL_MINUTES * 60000)
  };
}

function buildDefaultUser(tgUser) {
  const now = new Date();
  return {
    telegramUserId: String(tgUser.id),
    username: tgUser.username || "",
    displayName: [tgUser.first_name, tgUser.last_name].filter(Boolean).join(" ") || tgUser.username || "Chef",
    avatarUrl: tgUser.photo_url || "",
    chefPoints: 0,
    totalTaps: 0,
    mealsCooked: 0,
    currentEnergy: MAX_ENERGY,
    maxEnergy: MAX_ENERGY,
    energyUpdatedAt: now,
    streakCount: 1,
    lastActiveDate: todayKey(),
    lastStreakDate: todayKey(),
    createdAt: now,
    updatedAt: now
  };
}

function buildDefaultDaily(telegramUserId, dateKey) {
  return {
    telegramUserId,
    dateKey,
    tappedToday: 0,
    mealsCookedToday: 0,
    openedKitchenToday: true,
    completedTaskIds: ["open_kitchen"],
    createdAt: new Date(),
    updatedAt: new Date()
  };
}

function evaluateTasks(daily) {
  const completed = new Set(daily.completedTaskIds || []);
  for (const task of DAILY_TASKS) {
    if (task.type === "open" && daily.openedKitchenToday) completed.add(task.id);
    if (task.type === "tap" && Number(daily.tappedToday || 0) >= task.target) completed.add(task.id);
    if (task.type === "meal" && Number(daily.mealsCookedToday || 0) >= task.target) completed.add(task.id);
  }
  daily.completedTaskIds = [...completed];
  return daily;
}

function serializeState(user, daily) {
  const hydratedDaily = evaluateTasks({ ...daily });
  return {
    telegramUserId: user.telegramUserId,
    displayName: user.displayName,
    username: user.username,
    avatarUrl: user.avatarUrl,
    chefPoints: user.chefPoints,
    totalTaps: user.totalTaps,
    mealsCooked: user.mealsCooked,
    currentEnergy: user.currentEnergy,
    maxEnergy: user.maxEnergy,
    streakCount: user.streakCount,
    daily: {
      dateKey: hydratedDaily.dateKey,
      tappedToday: hydratedDaily.tappedToday,
      mealsCookedToday: hydratedDaily.mealsCookedToday,
      openedKitchenToday: hydratedDaily.openedKitchenToday,
      completedTaskIds: hydratedDaily.completedTaskIds
    },
    tasks: DAILY_TASKS.map((task) => ({
      ...task,
      progress:
        task.type === "tap" ? hydratedDaily.tappedToday :
        task.type === "meal" ? hydratedDaily.mealsCookedToday :
        hydratedDaily.openedKitchenToday ? 1 : 0,
      completed: hydratedDaily.completedTaskIds.includes(task.id)
    }))
  };
}

class InMemoryStore {
  constructor() {
    this.users = new Map();
    this.daily = new Map();
    this.memory = new Map();
  }
}

export async function createGameServices(cfg) {
  const db = await getDb(cfg);
  const memoryStore = new InMemoryStore();
  const rateMap = new Map();

  function rateLimit(userId) {
    const now = Date.now();
    const state = rateMap.get(userId) || { count: 0, ts: now };
    if (now - state.ts > 1000) {
      state.count = 0;
      state.ts = now;
    }
    state.count += 1;
    rateMap.set(userId, state);
    return state.count <= 8;
  }

  async function getUser(telegramUserId, tgUser) {
    if (!db) {
      let user = memoryStore.users.get(telegramUserId);
      if (!user && tgUser) {
        user = buildDefaultUser(tgUser);
        memoryStore.users.set(telegramUserId, user);
      }
      return user || null;
    }

    try {
      let user = await db.collection("users").findOne({ telegramUserId });
      if (!user && tgUser) {
        const insert = buildDefaultUser(tgUser);
        await db.collection("users").updateOne(
          { telegramUserId },
          {
            $setOnInsert: { ...insert, createdAt: insert.createdAt },
            $set: {
              username: insert.username,
              displayName: insert.displayName,
              avatarUrl: insert.avatarUrl,
              chefPoints: insert.chefPoints,
              totalTaps: insert.totalTaps,
              mealsCooked: insert.mealsCooked,
              currentEnergy: insert.currentEnergy,
              maxEnergy: insert.maxEnergy,
              energyUpdatedAt: insert.energyUpdatedAt,
              streakCount: insert.streakCount,
              lastActiveDate: insert.lastActiveDate,
              lastStreakDate: insert.lastStreakDate,
              updatedAt: insert.updatedAt
            }
          },
          { upsert: true }
        );
        user = await db.collection("users").findOne({ telegramUserId });
      }
      return user;
    } catch (error) {
      console.error("[db] users findOne/updateOne failed", { error: safeErr(error), collection: "users" });
      return null;
    }
  }

  async function saveUser(user) {
    delete user._id;
    delete user.createdAt;

    if (!db) {
      const current = memoryStore.users.get(user.telegramUserId) || {};
      memoryStore.users.set(user.telegramUserId, { ...current, ...user });
      return;
    }

    try {
      await db.collection("users").updateOne(
        { telegramUserId: user.telegramUserId },
        {
          $setOnInsert: { },
          $set: { ...user, updatedAt: new Date() }
        },
        { upsert: true }
      );
    } catch (error) {
      console.error("[db] users updateOne failed", { error: safeErr(error), collection: "users" });
      throw error;
    }
  }

  async function getDaily(telegramUserId, dateKey) {
    const key = `${telegramUserId}:${dateKey}`;
    if (!db) {
      return memoryStore.daily.get(key) || null;
    }
    try {
      return await db.collection("userdailyprogress").findOne({ telegramUserId, dateKey });
    } catch (error) {
      console.error("[db] userdailyprogress findOne failed", { error: safeErr(error), collection: "userdailyprogress" });
      return null;
    }
  }

  async function saveDaily(daily) {
    delete daily._id;
    delete daily.createdAt;
    const key = `${daily.telegramUserId}:${daily.dateKey}`;

    if (!db) {
      const current = memoryStore.daily.get(key) || buildDefaultDaily(daily.telegramUserId, daily.dateKey);
      memoryStore.daily.set(key, { ...current, ...daily, updatedAt: new Date() });
      return;
    }

    try {
      await db.collection("userdailyprogress").updateOne(
        { telegramUserId: daily.telegramUserId, dateKey: daily.dateKey },
        {
          $setOnInsert: { },
          $set: { ...daily, updatedAt: new Date() }
        },
        { upsert: true }
      );
    } catch (error) {
      console.error("[db] userdailyprogress updateOne failed", { error: safeErr(error), collection: "userdailyprogress" });
      throw error;
    }
  }

  async function resolvePlayerState(telegramUserId, tgUser) {
    const user = await getUser(telegramUserId, tgUser);
    const activeUser = user || buildDefaultUser(tgUser || { id: telegramUserId, first_name: "Chef" });
    const regen = regenEnergy(activeUser);
    activeUser.currentEnergy = regen.currentEnergy;
    activeUser.energyUpdatedAt = regen.energyUpdatedAt;

    const dateKey = todayKey();
    let daily = await getDaily(telegramUserId, dateKey);
    if (!daily) {
      daily = buildDefaultDaily(telegramUserId, dateKey);
      const lastStreakDate = activeUser.lastStreakDate || "";
      if (lastStreakDate === yesterdayKey()) {
        activeUser.streakCount = Number(activeUser.streakCount || 0) + 1;
      } else if (lastStreakDate !== dateKey) {
        activeUser.streakCount = 1;
      }
      activeUser.lastStreakDate = dateKey;
    } else {
      daily.openedKitchenToday = true;
    }

    activeUser.lastActiveDate = dateKey;
    activeUser.updatedAt = new Date();
    daily.updatedAt = new Date();
    daily = evaluateTasks(daily);

    await saveUser(activeUser);
    await saveDaily(daily);
    return serializeState(activeUser, daily);
  }

  async function bootstrapPlayer(tgUser) {
    return resolvePlayerState(String(tgUser.id), tgUser);
  }

  async function tapIngredient(telegramUserId, taps = 1) {
    if (!rateLimit(telegramUserId)) throw new Error("Too many taps. Slow down a bit.");
    const normalizedTaps = Math.max(1, Math.min(Number(taps) || 1, 5));
    const user = await getUser(telegramUserId);
    if (!user) throw new Error("Player not found.");

    const dateKey = todayKey();
    const daily = (await getDaily(telegramUserId, dateKey)) || buildDefaultDaily(telegramUserId, dateKey);
    const regen = regenEnergy(user);
    user.currentEnergy = regen.currentEnergy;
    user.energyUpdatedAt = regen.energyUpdatedAt;

    const spendable = Math.min(user.currentEnergy, normalizedTaps);
    if (spendable <= 0) throw new Error("Out of energy. Come back in a few minutes.");

    user.currentEnergy -= spendable;
    user.energyUpdatedAt = new Date();
    user.chefPoints += spendable * POINTS_PER_TAP;
    user.totalTaps += spendable;
    user.updatedAt = new Date();

    daily.tappedToday = Number(daily.tappedToday || 0) + spendable;
    daily.openedKitchenToday = true;
    daily.updatedAt = new Date();
    evaluateTasks(daily);

    await saveUser(user);
    await saveDaily(daily);
    return serializeState(user, daily);
  }

  async function cookMeal(telegramUserId) {
    const user = await getUser(telegramUserId);
    if (!user) throw new Error("Player not found.");

    const dateKey = todayKey();
    const daily = (await getDaily(telegramUserId, dateKey)) || buildDefaultDaily(telegramUserId, dateKey);
    const tapsBanked = Number(daily.tappedToday || 0) - Number(daily.mealsCookedToday || 0) * TAPS_PER_MEAL;
    if (tapsBanked < TAPS_PER_MEAL) throw new Error("You need more ingredient taps before cooking a meal.");

    user.mealsCooked += 1;
    user.chefPoints += MEAL_REWARD;
    user.updatedAt = new Date();

    daily.mealsCookedToday = Number(daily.mealsCookedToday || 0) + 1;
    daily.updatedAt = new Date();
    evaluateTasks(daily);

    await saveUser(user);
    await saveDaily(daily);
    return serializeState(user, daily);
  }

  async function getPlayerSummary(telegramUserId, tgUser = {}) {
    const state = await resolvePlayerState(telegramUserId, tgUser.id ? tgUser : { id: telegramUserId, first_name: tgUser.first_name || "Chef", username: tgUser.username || "" });
    return {
      chefPoints: state.chefPoints,
      currentEnergy: state.currentEnergy,
      maxEnergy: state.maxEnergy,
      streakCount: state.streakCount,
      mealsCooked: state.mealsCooked,
      completedTasks: state.tasks.filter((task) => task.completed).length,
      totalTasks: state.tasks.length
    };
  }

  async function getLeaderboard(telegramUserId = "") {
    let users = [];
    if (!db) {
      users = [...memoryStore.users.values()];
    } else {
      try {
        users = await db.collection("users").find({}, { projection: { displayName: 1, chefPoints: 1, mealsCooked: 1, streakCount: 1, telegramUserId: 1 } }).sort({ chefPoints: -1, mealsCooked: -1, streakCount: -1 }).limit(10).toArray();
      } catch (error) {
        console.error("[db] users leaderboard read failed", { error: safeErr(error), collection: "users" });
      }
    }

    const allUsers = !db ? [...memoryStore.users.values()].sort((a, b) => b.chefPoints - a.chefPoints) : users;
    const topPlayers = users.slice(0, 10).map((user) => ({
      displayName: user.displayName || "Chef",
      chefPoints: Number(user.chefPoints || 0),
      mealsCooked: Number(user.mealsCooked || 0),
      streakCount: Number(user.streakCount || 0)
    }));

    let you = null;
    if (telegramUserId) {
      if (!db) {
        const rank = allUsers.findIndex((user) => user.telegramUserId === telegramUserId) + 1;
        const current = memoryStore.users.get(telegramUserId);
        if (current) {
          you = {
            rank: rank || null,
            chefPoints: current.chefPoints || 0,
            displayName: current.displayName || "Chef"
          };
        }
      } else {
        const current = await getUser(telegramUserId);
        if (current) {
          const rank = 1 + await db.collection("users").countDocuments({ chefPoints: { $gt: current.chefPoints || 0 } });
          you = {
            rank,
            chefPoints: current.chefPoints || 0,
            displayName: current.displayName || "Chef"
          };
        }
      }
    }

    return { topPlayers, you };
  }

  async function saveMemoryTurn({ userId, chatId, role, text }) {
    const cleanText = String(text || "").slice(0, 2000);
    if (!cleanText) return;

    if (!db) {
      const key = `${userId}:${chatId}`;
      const list = memoryStore.memory.get(key) || [];
      list.push({ role, text: cleanText, ts: new Date() });
      memoryStore.memory.set(key, list.slice(-20));
      return;
    }

    try {
      await db.collection("memory_messages").insertOne({
        userId,
        platform: "telegram",
        chatId,
        role,
        text: cleanText,
        ts: new Date()
      });
    } catch (error) {
      console.error("[db] memory_messages insertOne failed", { error: safeErr(error), collection: "memory_messages" });
    }
  }

  async function getMemoryTurns(userId, chatId) {
    if (!db) {
      const key = `${userId}:${chatId}`;
      return (memoryStore.memory.get(key) || []).slice(-10);
    }

    try {
      const docs = await db.collection("memory_messages").find({ userId, chatId, platform: "telegram" }).sort({ ts: -1 }).limit(10).toArray();
      return docs.reverse();
    } catch (error) {
      console.error("[db] memory_messages find failed", { error: safeErr(error), collection: "memory_messages" });
      return [];
    }
  }

  async function clearMemory(userId, chatId) {
    if (!db) {
      memoryStore.memory.delete(`${userId}:${chatId}`);
      return;
    }
    try {
      await db.collection("memory_messages").deleteMany({ userId, chatId, platform: "telegram" });
    } catch (error) {
      console.error("[db] memory_messages deleteMany failed", { error: safeErr(error), collection: "memory_messages" });
    }
  }

  async function replyWithMemory({ userId, chatId, userText, botProfile }) {
    await saveMemoryTurn({ userId, chatId, role: "user", text: userText });
    const turns = await getMemoryTurns(userId, chatId);
    const lastUser = turns.filter((turn) => turn.role === "user").slice(-3).map((turn) => turn.text).join(" ");
    const answer = lastUser.toLowerCase().includes("leaderboard")
      ? "Use /leaderboard to see the top chefs, or open the Mini App leaderboard tab."
      : lastUser.toLowerCase().includes("profile")
      ? "Use /profile for your quick stats, or open the profile tab in TapChef for the full view."
      : `I can help with TapChef. ${botProfile.includes("/play") ? "Use /play to open the kitchen." : "Try /help."}`;
    await saveMemoryTurn({ userId, chatId, role: "assistant", text: answer });
    return answer;
  }

  return {
    bootstrapPlayer,
    tapIngredient,
    cookMeal,
    getLeaderboard,
    getPlayerSummary,
    clearMemory,
    replyWithMemory
  };
}

App.jsx.content:
import React, { useEffect, useMemo, useState } from "react";

function tg() {
  return window.Telegram?.WebApp;
}

function themeVars() {
  const app = tg();
  const p = app?.themeParams || {};
  return {
    bg: p.bg_color || "#1a1027",
    card: p.secondary_bg_color || "rgba(255,255,255,0.08)",
    text: p.text_color || "#fff7ed",
    hint: p.hint_color || "#d6c7bb",
    accent: p.button_color || "#f97316",
    accentText: p.button_text_color || "#fffaf5"
  };
}

function cx(...parts) {
  return parts.filter(Boolean).join(" ");
}

export default function App() {
  const webApp = useMemo(() => tg(), []);
  const [state, setState] = useState(null);
  const [tab, setTab] = useState("game");
  const [loading, setLoading] = useState(true);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState("");
  const [leaderboard, setLeaderboard] = useState({ topPlayers: [], you: null });
  const colors = themeVars();

  useEffect(() => {
    document.documentElement.style.setProperty("--bg", colors.bg);
    document.documentElement.style.setProperty("--card", colors.card);
    document.documentElement.style.setProperty("--text", colors.text);
    document.documentElement.style.setProperty("--hint", colors.hint);
    document.documentElement.style.setProperty("--accent", colors.accent);
    document.documentElement.style.setProperty("--accentText", colors.accentText);
    document.body.style.background = colors.bg;
    document.body.style.color = colors.text;
  }, [colors.bg, colors.card, colors.text, colors.hint, colors.accent, colors.accentText]);

  useEffect(() => {
    try {
      webApp?.ready();
      webApp?.expand();
      webApp?.disableVerticalSwipes?.();
    } catch {}
  }, [webApp]);

  useEffect(() => {
    let cancelled = false;
    async function bootstrap() {
      setLoading(true);
      setError("");
      try {
        const initData = webApp?.initData || "";
        const resp = await fetch("/api/auth/bootstrap", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ initData })
        });
        const json = await resp.json();
        if (cancelled) return;
        if (!json.ok) throw new Error(json.error || "Could not open your kitchen.");
        setState(json.state);
        await fetchLeaderboard(json.state.telegramUserId);
      } catch (err) {
        if (!cancelled) setError(err.message || "Could not open your kitchen.");
      } finally {
        if (!cancelled) setLoading(false);
      }
    }
    bootstrap();
    return () => {
      cancelled = true;
    };
  }, [webApp]);

  async function fetchLeaderboard(telegramUserId) {
    try {
      const resp = await fetch(`/api/leaderboard?telegramUserId=${encodeURIComponent(telegramUserId || "")}`);
      const json = await resp.json();
      if (json.ok) setLeaderboard({ topPlayers: json.topPlayers || [], you: json.you || null });
    } catch {}
  }

  async function postAction(url, body) {
    if (!state?.telegramUserId) return;
    setBusy(true);
    setError("");
    try {
      webApp?.HapticFeedback?.impactOccurred?.("light");
      const resp = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
      });
      const json = await resp.json();
      if (!json.ok) throw new Error(json.error || "Action failed.");
      setState(json.state);
      await fetchLeaderboard(json.state.telegramUserId);
    } catch (err) {
      setError(err.message || "Action failed.");
      webApp?.HapticFeedback?.notificationOccurred?.("error");
    } finally {
      setBusy(false);
    }
  }

  const mealsReady = state ? Math.floor((state.daily.tappedToday - state.daily.mealsCookedToday * 20) / 20) : 0;

  return (
    <div className="min-h-screen px-4 pt-4 pb-8" style={{ paddingTop: "max(1rem, env(safe-area-inset-top))", paddingBottom: "max(1.5rem, env(safe-area-inset-bottom))" }}>
      <div className="mx-auto w-full max-w-md space-y-4">
        <header className="rounded-[28px] border border-white/10 bg-[radial-gradient(circle_at_top,_rgba(249,115,22,0.35),_rgba(26,16,39,0.95)_55%)] p-5 shadow-2xl">
          <div className="flex items-start justify-between gap-3">
            <div>
              <p className="text-xs uppercase tracking-[0.24em] text-orange-200/80">TapChef</p>
              <h1 className="mt-1 text-3xl font-black leading-none">Cook fast. Tap smart.</h1>
              <p className="mt-2 text-sm text-orange-50/80">Earn Chef Points, finish daily tasks, and keep your kitchen streak alive.</p>
            </div>
            <div className="rounded-2xl bg-white/10 px-3 py-2 text-right backdrop-blur">
              <div className="text-[11px] uppercase tracking-wide text-orange-100/70">Streak</div>
              <div className="text-2xl font-bold">{state?.streakCount ?? "-"}</div>
            </div>
          </div>
        </header>

        <nav className="grid grid-cols-4 gap-2 rounded-2xl bg-white/5 p-1">
          {[
            ["game", "Game"],
            ["tasks", "Tasks"],
            ["profile", "Profile"],
            ["leaders", "Leaders"]
          ].map(([key, label]) => (
            <button
              key={key}
              className={cx("min-h-[44px] rounded-xl text-sm font-semibold transition", tab === key ? "bg-orange-500 text-white shadow-lg" : "text-orange-50/80")}
              onClick={() => setTab(key)}
            >
              {label}
            </button>
          ))}
        </nav>

        {loading ? (
          <section className="space-y-3 rounded-3xl bg-white/6 p-4">
            <div className="h-5 w-32 animate-pulse rounded bg-white/10" />
            <div className="h-24 animate-pulse rounded-3xl bg-white/10" />
            <div className="h-16 animate-pulse rounded-2xl bg-white/10" />
          </section>
        ) : error && !state ? (
          <section className="rounded-3xl border border-red-300/20 bg-red-500/10 p-4 text-sm text-red-50">
            {error}
          </section>
        ) : null}

        {state ? (
          <>
            {tab === "game" ? (
              <section className="space-y-4">
                <div className="grid grid-cols-3 gap-3">
                  <StatCard label="Chef Points" value={state.chefPoints} />
                  <StatCard label="Energy" value={`${state.currentEnergy}/${state.maxEnergy}`} />
                  <StatCard label="Meals" value={state.mealsCooked} />
                </div>

                <div className="rounded-[32px] border border-white/10 bg-white/8 p-5 text-center shadow-xl">
                  <p className="text-sm text-orange-100/70">Main ingredient</p>
                  <button
                    className="mx-auto mt-4 flex h-48 w-48 items-center justify-center rounded-full border border-orange-200/25 bg-[radial-gradient(circle_at_30%_30%,_#fdba74,_#ea580c_60%,_#7c2d12)] text-7xl shadow-[0_18px_50px_rgba(249,115,22,0.35)] transition active:scale-95 disabled:opacity-60"
                    disabled={busy || state.currentEnergy <= 0}
                    onClick={() => postAction("/api/game/tap", { telegramUserId: state.telegramUserId, taps: 1 })}
                  >
                    🍅
                  </button>
                  <p className="mt-4 text-sm text-orange-50/80">Each tap uses 1 energy and gives 1 Chef Point.</p>
                  <div className="mt-4 flex items-center justify-between rounded-2xl bg-black/20 px-4 py-3 text-sm text-orange-50/85">
                    <span>Meals ready</span>
                    <span className="font-bold">{Math.max(0, mealsReady)}</span>
                  </div>
                  <button
                    className="mt-4 min-h-[48px] w-full rounded-2xl bg-orange-500 px-4 text-base font-bold text-white shadow-lg transition active:scale-[0.99] disabled:opacity-60"
                    disabled={busy || mealsReady < 1}
                    onClick={() => postAction("/api/game/cook", { telegramUserId: state.telegramUserId })}
                  >
                    Cook Meal
                  </button>
                </div>
              </section>
            ) : null}

            {tab === "tasks" ? (
              <section className="space-y-3">
                {state.tasks.map((task) => (
                  <div key={task.id} className="rounded-3xl border border-white/10 bg-white/8 p-4">
                    <div className="flex items-start justify-between gap-3">
                      <div>
                        <p className="text-base font-semibold">{task.label}</p>
                        <p className="mt-1 text-sm text-orange-50/70">{task.progress}/{task.target}</p>
                      </div>
                      <span className={cx("rounded-full px-3 py-1 text-xs font-bold", task.completed ? "bg-emerald-400/20 text-emerald-100" : "bg-white/10 text-orange-50/70")}>{task.completed ? "Done" : "Cooking"}</span>
                    </div>
                    <div className="mt-3 h-2 overflow-hidden rounded-full bg-black/20">
                      <div className="h-full rounded-full bg-orange-400" style={{ width: `${Math.min(100, Math.round((task.progress / task.target) * 100))}%` }} />
                    </div>
                  </div>
                ))}
              </section>
            ) : null}

            {tab === "profile" ? (
              <section className="space-y-3 rounded-3xl border border-white/10 bg-white/8 p-4">
                <ProfileRow label="Chef" value={state.displayName} />
                <ProfileRow label="Chef Points" value={state.chefPoints} />
                <ProfileRow label="Energy" value={`${state.currentEnergy}/${state.maxEnergy}`} />
                <ProfileRow label="Total taps" value={state.totalTaps} />
                <ProfileRow label="Meals cooked" value={state.mealsCooked} />
                <ProfileRow label="Daily streak" value={state.streakCount} />
                <ProfileRow label="Tasks done" value={`${state.tasks.filter((task) => task.completed).length}/${state.tasks.length}`} />
              </section>
            ) : null}

            {tab === "leaders" ? (
              <section className="space-y-3">
                <div className="rounded-3xl border border-white/10 bg-white/8 p-4">
                  <p className="text-sm text-orange-50/70">Your rank</p>
                  <p className="mt-1 text-2xl font-black">{leaderboard.you?.rank || "Unranked"}</p>
                </div>
                {leaderboard.topPlayers.length ? leaderboard.topPlayers.map((player, index) => (
                  <div key={`${player.displayName}-${index}`} className="flex items-center justify-between rounded-3xl border border-white/10 bg-white/8 p-4">
                    <div>
                      <p className="text-sm text-orange-50/70">#{index + 1}</p>
                      <p className="text-base font-semibold">{player.displayName}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-lg font-black">{player.chefPoints}</p>
                      <p className="text-xs text-orange-50/70">{player.mealsCooked} meals</p>
                    </div>
                  </div>
                )) : <EmptyCard text="No chefs on the board yet. Start tapping to claim the first spot." />}
              </section>
            ) : null}
          </>
        ) : null}

        {error && state ? (
          <div className="rounded-2xl border border-red-300/20 bg-red-500/10 px-4 py-3 text-sm text-red-50">{error}</div>
        ) : null}
      </div>
    </div>
  );
}

function StatCard({ label, value }) {
  return (
    <div className="rounded-3xl border border-white/10 bg-white/8 p-4 shadow-lg">
      <p className="text-xs uppercase tracking-wide text-orange-50/65">{label}</p>
      <p className="mt-2 text-2xl font-black">{value}</p>
    </div>
  );
}

function ProfileRow({ label, value }) {
  return (
    <div className="flex items-center justify-between gap-3 rounded-2xl bg-black/15 px-4 py-3">
      <span className="text-sm text-orange-50/70">{label}</span>
      <span className="text-sm font-semibold text-right">{value}</span>
    </div>
  );
}

function EmptyCard({ text }) {
  return <div className="rounded-3xl border border-white/10 bg-white/8 p-4 text-sm text-orange-50/75">{text}</div>;
}

