@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg: #1a1027;
  --card: rgba(255, 255, 255, 0.08);
  --text: #fff7ed;
  --hint: #d6c7bb;
  --accent: #f97316;
  --accentText: #fffaf5;
}

html,
body,
#root {
  min-height: 100%;
}

body {
  margin: 0;
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  background: var(--bg);
  color: var(--text);
  overscroll-behavior: none;
}

* {
  box-sizing: border-box;
  -webkit-tap-highlight-color: transparent;
}

button {
  font: inherit;
}

